import { UserProfile, WeeklyStats, Task, TaskType, VerificationStatus } from './types';
import { calculateWeeklyRating } from './services/geminiService';

const MOCK_USER: UserProfile = {
  name: "Alex Dev",
  email: "alex@example.com",
  avatarUrl: "https://picsum.photos/200/200",
  weeklyGoalHours: 80,
  currentStreak: 4
};

const INITIAL_STATS: WeeklyStats = {
  weekId: '2024-W22',
  goalHours: 80,
  completedHours: 0,
  screenTimeHours: 0,
  rating: 0,
  streakActive: true
};

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [currentView, setCurrentView] = useState('dashboard');
  const [user, setUser] = useState<UserProfile>(MOCK_USER);
  const [stats, setStats] = useState<WeeklyStats>(INITIAL_STATS);
  const [tasks, setTasks] = useState<Task[]>([]);

  // Load state from local storage on mount
  useEffect(() => {
    const savedAuth = localStorage.getItem('focusforge_auth');
    if (savedAuth === 'true') setIsAuthenticated(true);

    // Load tasks/stats logic would go here in real app
  }, []);

  const handleLogin = () => {
    localStorage.setItem('focusforge_auth', 'true');
    setIsAuthenticated(true);
  };

  const handleLogout = () => {
    localStorage.removeItem('focusforge_auth');
    setIsAuthenticated(false);
  };

  const updateCompletedHours = async (hoursToAdd: number) => {
     setStats(prev => {
       const newCompleted = prev.completedHours + hoursToAdd;
       // We calculate rating asynchronously but for UI responsiveness we do it in effect usually
       // Here simplified
       return {
         ...prev,
         completedHours: newCompleted
       }
     });

     // Recalculate Rating
     const newRating = await calculateWeeklyRating(stats.completedHours + hoursToAdd, stats.goalHours, stats.screenTimeHours);
     setStats(prev => ({ ...prev, rating: newRating }));
  };

  const handleScreenTimeSubmit = async (hours: number, image: string) => {
     setStats(prev => ({
       ...prev,
       screenTimeHours: prev.screenTimeHours + hours
     }));
     // Recalculate Rating
     const newRating = await calculateWeeklyRating(stats.completedHours, stats.goalHours, stats.screenTimeHours + hours);
     setStats(prev => ({ ...prev, rating: newRating }));
  };

  if (!isAuthenticated) {
    return <Auth onLogin={handleLogin} />;
  }

  return (
    <div className="flex flex-col md:flex-row min-h-screen bg-[#020617] text-slate-50 font-sans">
      <Sidebar 
        user={user} 
        currentView={currentView} 
        setView={setCurrentView} 
        onLogout={handleLogout}
      />

      <main className="flex-1 md:ml-64 p-4 md:p-8 overflow-y-auto h-screen">
        <div className="max-w-7xl mx-auto h-full">
          {currentView === 'dashboard' && <Dashboard user={user} stats={stats} tasks={tasks} />}
          {currentView === 'tasks' && <TaskList tasks={tasks} setTasks={setTasks} user={user} updateCompletedHours={updateCompletedHours} />}
          {currentView === 'screentime' && <ScreenTimeUpload onSubmit={handleScreenTimeSubmit} />}

          {/* Simple Placeholder for History */}
          {currentView === 'history' && (
            <div className="flex items-center justify-center h-full text-slate-500">
               <div className="text-center">
                 <p className="text-xl">History feature coming soon.</p>
                 <p className="text-sm">Weekly logs will be archived here.</p>
               </div>
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

