      const parsedUser = JSON.parse(savedUser);
      setUser(parsedUser);
      setIsAuthenticated(true);
      fetchUserData(parsedUser.googleId);
    }
  }, []);

  const fetchUserData = async (googleId: string) => {
    setIsLoading(true);
    const currentWeekId = getCurrentWeekId();

    // 0. Fetch User Profile to get goal
    const { data: profile } = await supabase.from('profiles').select('*').eq('google_id', googleId).single();
    if (profile && user) {
       // Update user goal from DB
       const updatedUser = { ...user, weeklyGoalHours: profile.weekly_goal_hours || 80 };
       setUser(updatedUser);
       // Save to local storage for persistence
       localStorage.setItem('focusforge_user', JSON.stringify(updatedUser));
    }

    // 1. Fetch History
    const { data: historyData } = await supabase
      .from('weekly_stats')
      .select('*')
      .eq('user_id', googleId)
      .neq('week_id', currentWeekId)
      .order('week_id', { ascending: true }); // Ensure chronological order

    let calculatedStreak = 0;

    if (historyData) {
      // Map DB snake_case to camelCase matches types
      const formattedHistory: HistoryEntry[] = historyData.map((h: any) => ({
        id: h.id,
        weekId: h.week_id,
        goalHours: h.goal_hours,
        completedHours: h.completed_hours,
        screenTimeHours: h.screen_time_hours,
        rating: h.rating,
        streakActive: h.streak_active,
        startDate: h.start_date,
        endDate: h.end_date
      }));
      setHistory(formattedHistory);

      // Recalculate Streak: Count consecutive past weeks where goal was met
      // Sort descending to count from most recent back
      const reversedHistory = [...formattedHistory].sort((a, b) => b.weekId.localeCompare(a.weekId));

      for (const entry of reversedHistory) {
         if (entry.completedHours >= entry.goalHours) {
           calculatedStreak++;
         } else {
           break; 
         }
      }
    } else {
      setHistory([]);
    }

    // Update User Streak
    setUser((prev) => {
        if (!prev) return null;
        const updated = { ...prev, currentStreak: calculatedStreak };
        localStorage.setItem('focusforge_user', JSON.stringify(updated));
        return updated;
    });

    // 2. Fetch Current Week Stats or Create
    const { data: currentStats, error } = await supabase
      .from('weekly_stats')
      .select('*')
      .eq('user_id', googleId)
      .eq('week_id', currentWeekId)
      .single();

    if (currentStats) {
      setStats({
        weekId: currentStats.week_id,
        goalHours: currentStats.goal_hours,
        completedHours: currentStats.completed_hours,
        screenTimeHours: currentStats.screen_time_hours,
        rating: currentStats.rating,
        streakActive: currentStats.streak_active,
        startDate: currentStats.start_date,
        endDate: currentStats.end_date
      });
    } else {
      // Create new week entry
      const startOfWeek = new Date();
      startOfWeek.setDate(startOfWeek.getDate() - startOfWeek.getDay() + 1); // Monday
      const endOfWeek = new Date(startOfWeek);
      endOfWeek.setDate(endOfWeek.getDate() + 6); // Sunday

      const currentGoal = profile?.weekly_goal_hours || 80;

      const newStats: WeeklyStats = {
        weekId: currentWeekId,
        startDate: startOfWeek.toLocaleDateString(),
        endDate: endOfWeek.toLocaleDateString(),
        goalHours: currentGoal,
        completedHours: 0,
        screenTimeHours: 0,
        rating: 0,
        streakActive: true
      };

      const { error: insertError } = await supabase.from('weekly_stats').insert({
        user_id: googleId,
        week_id: newStats.weekId,
        start_date: newStats.startDate,
        end_date: newStats.endDate,
        goal_hours: newStats.goalHours
      });

      if (!insertError) setStats(newStats);
    }

    // 3. Fetch Tasks
    const { data: tasksData } = await supabase
      .from('tasks')
      .select('*')
      .eq('user_id', googleId)
      .order('created_at', { ascending: false });

    if (tasksData) {
      const formattedTasks: Task[] = tasksData.map((t: any) => ({
        id: t.id,
        title: t.title,
        description: t.description,
        type: t.type,
        durationHours: t.duration_hours,
        createdAt: t.created_at,
        completedAt: t.completed_at,
        status: t.status,
        proofImage: t.proof_image,
        rejectionReason: t.rejection_reason
      }));
      setTasks(formattedTasks);
    }

    setIsLoading(false);
  };

  const handleLogin = async (userData: any) => {
    // 1. Try to fetch existing profile first to get their specific goal
    const { data: existingProfile } = await supabase.from('profiles').select('weekly_goal_hours').eq('google_id', userData.googleId).single();

    const userGoal = existingProfile?.weekly_goal_hours || 80;

    // 2. Upsert User to Supabase
    const { error } = await supabase.from('profiles').upsert({
      google_id: userData.googleId,
      email: userData.email,
      name: userData.name,
      avatar_url: userData.avatarUrl,
      // Only set default if it's a new insert (though upsert overwrites, we want to preserve if possible, 
      // but without complex logic, we just ensure the column exists. 
      // Actually standard upsert overwrites. We should only update relevant fields or use ignore duplicates?
      // For now, let's just update identity info and keep goal if we fetched it, or set default.
      weekly_goal_hours: userGoal 
    }, { onConflict: 'google_id' });

    if (error) {
      console.error("Supabase Login Error", error);
    }

    const newUser: UserProfile = {
      name: userData.name,
      email: userData.email,
      avatarUrl: userData.avatarUrl,
      googleId: userData.googleId,
      weeklyGoalHours: userGoal, 
      currentStreak: 0 
    };
    setUser(newUser);
    localStorage.setItem('focusforge_user', JSON.stringify(newUser));
    setIsAuthenticated(true);
    fetchUserData(userData.googleId);
  };

  const handleLogout = () => {
    localStorage.removeItem('focusforge_user');
    setUser(null);
    setStats(null);
    setTasks([]);
    setHistory([]);
    setIsAuthenticated(false);
  };

  const updateWeeklyGoal = async (newGoal: number) => {
    if (!user) return;

    // Update State
    const updatedUser = { ...user, weeklyGoalHours: newGoal };
    setUser(updatedUser);
    localStorage.setItem('focusforge_user', JSON.stringify(updatedUser));

    // Update DB Profile
    await supabase.from('profiles').update({ weekly_goal_hours: newGoal }).eq('google_id', user.googleId);

    // Update Current Week Stats Goal if exists
    if (stats) {
        setStats({ ...stats, goalHours: newGoal });
        await supabase.from('weekly_stats')
            .update({ goal_hours: newGoal })
            .eq('user_id', user.googleId)
            .eq('week_id', stats.weekId);
    }
  };

  const updateCompletedHours = async (hoursToAdd: number) => {
     if (!user || !stats) return;

     const newCompleted = stats.completedHours + hoursToAdd;
     const newRating = await calculateWeeklyRating(
       newCompleted, 
       stats.goalHours, 
       stats.screenTimeHours
     );

     // Update local state
     setStats(prev => prev ? ({ ...prev, completedHours: newCompleted, rating: newRating }) : null);

     // Update DB
     await supabase
       .from('weekly_stats')
       .update({ completed_hours: newCompleted, rating: newRating })
       .eq('user_id', user.googleId)
       .eq('week_id', stats.weekId);
  };

  const handleScreenTimeSubmit = async (hours: number, image: string) => {
     if (!user || !stats) return;

     const newScreenTime = stats.screenTimeHours + hours;
     const newRating = await calculateWeeklyRating(
       stats.completedHours, 
       stats.goalHours, 
       newScreenTime
     );

     setStats(prev => prev ? ({ ...prev, screenTimeHours: newScreenTime, rating: newRating }) : null);

     // Update DB
     await supabase
       .from('weekly_stats')
       .update({ screen_time_hours: newScreenTime, rating: newRating })
       .eq('user_id', user.googleId)
       .eq('week_id', stats.weekId);
  };

  if (!isAuthenticated || !user) {
    return <Auth onLogin={handleLogin} />;
  }

  if (isLoading || !stats) {
    return <div className="min-h-screen bg-[#020617] flex items-center justify-center text-white">Loading your dashboard...</div>;
  }

  return (
    <div className="flex flex-col md:flex-row min-h-screen bg-[#020617] text-slate-50 font-sans">
      <Sidebar 
        user={user} 
        currentView={currentView} 
        setView={setCurrentView} 
        onLogout={handleLogout}
        onUpdateGoal={updateWeeklyGoal}
      />

      <main className="flex-1 md:ml-64 p-4 md:p-8 overflow-y-auto h-screen">
        <div className="max-w-7xl mx-auto h-full">
          {currentView === 'dashboard' && <Dashboard user={user} stats={stats} tasks={tasks} />}
          {currentView === 'tasks' && <TaskList tasks={tasks} setTasks={setTasks} user={user} updateCompletedHours={updateCompletedHours} />}
          {currentView === 'screentime' && <ScreenTimeUpload onSubmit={handleScreenTimeSubmit} />}
          {currentView === 'history' && <History history={[...history, { ...stats, id: 'current' } as HistoryEntry]} />}
        </div>
      </main>
    </div>
  );
};

export default App;

import { createClient } from '@supabase/supabase-js';

// Helper to safely get Env Vars
const getEnv = (key: string) => {
  // @ts-ignore
  if (typeof import.meta !== 'undefined' && import.meta.env) {
    // @ts-ignore
    return import.meta.env[`VITE_${key}`] || import.meta.env[key];
  }
  // @ts-ignore
  if (typeof process !== 'undefined' && process.env) {
    // @ts-ignore
    return process.env[`REACT_APP_${key}`] || process.env[key];
  }
  return "";
};

const supabaseUrl = getEnv('SUPABASE_URL');
const supabaseAnonKey = getEnv('SUPABASE_ANON_KEY');

export const supabase = createClient(supabaseUrl, supabaseAnonKey);

export const uploadProof = async (file: File, userId: string, folder: 'tasks' | 'screentime') => {
  const fileExt = file.name.split('.').pop();
  const fileName = `${Date.now()}_${Math.random().toString(36).substring(2)}.${fileExt}`;
  const filePath = `${userId}/${folder}/${fileName}`;

  const { error: uploadError } = await supabase.storage
    .from('proofs')
    .upload(filePath, file);

  if (uploadError) {
    throw uploadError;
  }

  const { data } = supabase.storage
    .from('proofs')
    .getPublicUrl(filePath);

  return data.publicUrl;
};

import React, { useState, useRef } from 'react';
import { Icons } from './Icons';
import { Task, TaskType, VerificationStatus, UserProfile } from '../types';
import { verifyTaskProof } from '../services/geminiService';
import { supabase, uploadProof } from '../services/supabase';

interface TaskListProps {
  tasks: Task[];
  user: UserProfile;
  setTasks: React.Dispatch<React.SetStateAction<Task[]>>;
  updateCompletedHours: (hours: number) => void;
}

export const TaskList: React.FC<TaskListProps> = ({ tasks, user, setTasks, updateCompletedHours }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [verifyingId, setVerifyingId] = useState<string | null>(null);

  // New Task Form State
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskDesc, setNewTaskDesc] = useState('');
  const [newTaskType, setNewTaskType] = useState<TaskType>(TaskType.WORK);
  const [newTaskDuration, setNewTaskDuration] = useState<number>(1);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const [selectedTaskForUpload, setSelectedTaskForUpload] = useState<string | null>(null);

  // Daily Limit Calculation
  const dailyLimit = user.weeklyGoalHours / 7;
  // Calculate today's verified + pending tasks duration
  const todayTasks = tasks.filter(t => {
      const isToday = new Date(t.createdAt).toDateString() === new Date().toDateString();
      return isToday && t.status !== VerificationStatus.REJECTED;
  });
  const todayUsed = todayTasks.reduce((acc, t) => acc + t.durationHours, 0);

  const handleAddTask = async () => {
    if (!newTaskTitle || newTaskDuration <= 0) return;

    if (todayUsed + newTaskDuration > dailyLimit) {
      alert(`Cannot add task. This would exceed your daily calculated limit of ${dailyLimit.toFixed(1)} hours.`);
      return;
    }

    const tempId = crypto.randomUUID();
    const newTask: Task = {
      id: tempId,
      title: newTaskTitle,
      description: newTaskDesc,
      type: newTaskType,
      durationHours: newTaskDuration,
      createdAt: Date.now(),
      status: VerificationStatus.PENDING
    };

    // Optimistic Update
    setTasks(prev => [newTask, ...prev]);
    setIsModalOpen(false);
    resetForm();

    // DB Insert
    const { data, error } = await supabase.from('tasks').insert({
      user_id: user.googleId,
      title: newTask.title,
      description: newTask.description,
      type: newTask.type,
      duration_hours: newTask.durationHours,
      status: newTask.status,
      created_at: newTask.createdAt
    }).select();

    // Update with real ID from DB if successful
    if (data && data[0]) {
      setTasks(prev => prev.map(t => t.id === tempId ? { ...t, id: data[0].id } : t));
    }
    if (error) {
      console.error("Error creating task", error);
      // Revert optimistic update
      setTasks(prev => prev.filter(t => t.id !== tempId));
      alert("Failed to save task to database.");
    }
  };

  const resetForm = () => {
    setNewTaskTitle('');
    setNewTaskDesc('');
    setNewTaskDuration(1);
    setNewTaskType(TaskType.WORK);
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !selectedTaskForUpload) return;

    const taskIndex = tasks.findIndex(t => t.id === selectedTaskForUpload);
    if (taskIndex === -1) return;
    const taskToVerify = tasks[taskIndex];

    // Optimistic update to VERIFYING
    setVerifyingId(selectedTaskForUpload);
    updateTaskStatus(selectedTaskForUpload, VerificationStatus.VERIFYING);

    // 1. Read as Base64 for AI Verification
    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64String = reader.result as string;

      // Call AI Service
      const result = await verifyTaskProof(taskToVerify, base64String, file.type);

      let newStatus = VerificationStatus.PENDING;
      let rejectionReason = "";
      let publicUrl = "";

      if (result.verified) {
         try {
           // 2. Upload to Supabase Storage if verified
           publicUrl = await uploadProof(file, user.googleId, 'tasks');
           newStatus = VerificationStatus.VERIFIED;

           setTasks(prev => prev.map(t => 
               t.id === selectedTaskForUpload 
               ? { ...t, status: newStatus, completedAt: Date.now(), proofImage: publicUrl } 
               : t
           ));
           updateCompletedHours(taskToVerify.durationHours);
         } catch (uploadErr) {
           console.error("Upload failed", uploadErr);
           alert("Verification successful, but image upload failed.");
           // Fallback to verified without image URL or keep local base64 if needed
           newStatus = VerificationStatus.VERIFIED; 
         }
      } else {
         newStatus = VerificationStatus.REJECTED;
         rejectionReason = result.reason || "Verification failed";
         setTasks(prev => prev.map(t => 
             t.id === selectedTaskForUpload 
             ? { ...t, status: newStatus, rejectionReason: rejectionReason } 
             : t
         ));
         alert(`Verification Failed: ${rejectionReason}`);
      }

      setVerifyingId(null);

      // Update DB
      await supabase.from('tasks').update({
        status: newStatus,
        completed_at: result.verified ? Date.now() : null,
        proof_image: publicUrl || null,
        rejection_reason: rejectionReason
      }).eq('id', selectedTaskForUpload);

      setSelectedTaskForUpload(null);
    };
    reader.readAsDataURL(file);
  };

  const updateTaskStatus = (id: string, status: VerificationStatus) => {
    setTasks(prev => prev.map(t => t.id === id ? { ...t, status } : t));
  };

  const triggerUpload = (id: string) => {
    setSelectedTaskForUpload(id);
    fileInputRef.current?.click();
  };

  return (
    <div className="pb-20 md:pb-0 h-full overflow-y-auto">
      <div className="flex justify-between items-center mb-6">
        <div>
          <h2 className="text-2xl font-bold text-white">Tasks</h2>
          <p className="text-slate-400 text-sm">
             Today's Load: <span className={`${todayUsed > dailyLimit ? 'text-red-400' : 'text-indigo-400'}`}>{todayUsed.toFixed(1)}h</span> / {dailyLimit.toFixed(1)}h limit
          </p>
        </div>
        <button 
          onClick={() => setIsModalOpen(true)}
          className="bg-indigo-600 hover:bg-indigo-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-colors font-medium shadow-lg shadow-indigo-900/20"
        >
          <Icons.Plus className="w-5 h-5" />
          Add Task
        </button>
      </div>

      <div className="space-y-4">
        {tasks.length === 0 && (
            <div className="text-center py-20 text-slate-500">
                <Icons.CheckCircle className="w-16 h-16 mx-auto mb-4 opacity-20" />
                <p>No tasks yet. Start forging your week!</p>
            </div>
        )}

        {tasks.map(task => (
          <div key={task.id} className={`bg-slate-900 border ${task.status === VerificationStatus.VERIFIED ? 'border-green-900/50 bg-green-900/5' : task.status === VerificationStatus.REJECTED ? 'border-red-900/50' : 'border-slate-800'} rounded-xl p-5 flex flex-col md:flex-row justify-between items-start md:items-center gap-4 transition-all hover:border-slate-700`}>
            <div className="flex-1">
              <div className="flex items-center gap-2 mb-1">
                <span className={`text-xs px-2 py-0.5 rounded border ${task.type === TaskType.STUDY ? 'bg-indigo-950/50 border-indigo-900 text-indigo-400' : 'bg-teal-950/50 border-teal-900 text-teal-400'}`}>
                  {task.type}
                </span>
                <span className="text-xs text-slate-500 flex items-center gap-1">
                  <Icons.Clock className="w-3 h-3" /> {task.durationHours}h
                </span>
                {task.status === VerificationStatus.REJECTED && (
                    <span className="text-xs text-red-400 bg-red-950/30 px-2 rounded">Rejected: {task.rejectionReason}</span>
                )}
              </div>
              <h3 className="text-lg font-semibold text-slate-100">{task.title}</h3>
              <p className="text-slate-400 text-sm mt-1">{task.description}</p>
            </div>

            <div className="w-full md:w-auto flex justify-end">
               {task.status === VerificationStatus.VERIFIED ? (
                 <div className="flex items-center gap-2 text-green-500 px-4 py-2 bg-green-950/20 rounded-lg border border-green-900/50">
                    <Icons.CheckCircle className="w-5 h-5" />
                    <span className="font-medium">Completed</span>
                 </div>
               ) : verifyingId === task.id ? (
                 <div className="flex items-center gap-2 text-indigo-400 px-4 py-2 animate-pulse">
                    <Icons.Shield className="w-5 h-5 animate-bounce" />
                    <span>AI Verifying...</span>
                 </div>
               ) : (
                 <button 
                   onClick={() => triggerUpload(task.id)}
                   className="w-full md:w-auto flex items-center justify-center gap-2 bg-slate-800 hover:bg-slate-700 text-slate-200 px-4 py-2 rounded-lg border border-slate-700 transition-colors"
                 >
                   <Icons.Upload className="w-4 h-4" />
                   Submit Proof
                 </button>
               )}
            </div>
          </div>
        ))}
      </div>

      {/* Hidden File Input */}
      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={handleFileUpload} 
        accept="image/*" 
        className="hidden" 
      />

      {/* Add Task Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-slate-900 border border-slate-700 w-full max-w-md rounded-2xl p-6 shadow-2xl">
            <h3 className="text-xl font-bold text-white mb-4">New Task</h3>

            <div className="space-y-4">
              <div>
                <label className="block text-sm text-slate-400 mb-1">Title</label>
                <input 
                  type="text" 
                  value={newTaskTitle}
                  onChange={(e) => setNewTaskTitle(e.target.value)}
                  className="w-full bg-slate-800 border border-slate-700 rounded-lg px-3 py-2 text-white focus:outline-none focus:border-indigo-500"
                  placeholder="e.g., Complete Chapter 4 Math"
                />
              </div>

              <div>
                <label className="block text-sm text-slate-400 mb-1">Description (for AI Verification)</label>
                <textarea 
                  value={newTaskDesc}
                  onChange={(e) => setNewTaskDesc(e.target.value)}
                  className="w-full bg-slate-800 border border-slate-700 rounded-lg px-3 py-2 text-white focus:outline-none focus:border-indigo-500 h-24 resize-none"
                  placeholder="Describe exactly what will be visible in the proof..."
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                   <label className="block text-sm text-slate-400 mb-1">Type</label>
                   <select 
                    value={newTaskType}
                    onChange={(e) => setNewTaskType(e.target.value as TaskType)}
                    className="w-full bg-slate-800 border border-slate-700 rounded-lg px-3 py-2 text-white focus:outline-none focus:border-indigo-500"
                   >
                     <option value={TaskType.STUDY}>Study</option>
                     <option value={TaskType.WORK}>Work</option>
                   </select>
                </div>
                <div>
                   <label className="block text-sm text-slate-400 mb-1">Duration (Hours)</label>
                   <input 
                    type="number" 
                    min="0.5"
                    step="0.5"
                    value={newTaskDuration}
                    onChange={(e) => setNewTaskDuration(parseFloat(e.target.value))}
                    className="w-full bg-slate-800 border border-slate-700 rounded-lg px-3 py-2 text-white focus:outline-none focus:border-indigo-500"
                   />
                </div>
              </div>
            </div>

            <div className="flex gap-3 mt-6">
              <button 
                onClick={() => setIsModalOpen(false)}
                className="flex-1 px-4 py-2 bg-slate-800 text-slate-300 rounded-lg hover:bg-slate-700"
              >
                Cancel
              </button>
              <button 
                onClick={handleAddTask}
                className="flex-1 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 font-medium"
              >
                Create
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { Icons } from './Icons';
import { UserProfile } from '../types';
import { uploadProof } from '../services/supabase';

interface ScreenTimeUploadProps {
  user: UserProfile;
  onSubmit: (hours: number, imageUrl: string) => void;
}

export const ScreenTimeUpload: React.FC<ScreenTimeUploadProps> = ({ user, onSubmit }) => {
  const [hours, setHours] = useState<number>(0);
  const [imagePreview, setImagePreview] = useState<string | null>(null);
  const [file, setFile] = useState<File | null>(null);
  const [isUploading, setIsUploading] = useState(false);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0];
    if (selectedFile) {
      setFile(selectedFile);
      const reader = new FileReader();
      reader.onloadend = () => {
        setImagePreview(reader.result as string);
      };
      reader.readAsDataURL(selectedFile);
    }
  };

  const handleSubmit = async () => {
    if (hours >= 0 && file && user) {
      try {
        setIsUploading(true);
        const url = await uploadProof(file, user.googleId, 'screentime');
        onSubmit(hours, url);
        setHours(0);
        setImagePreview(null);
        setFile(null);
        alert("Screen time logged successfully.");
      } catch (error) {
        console.error(error);
        alert("Failed to upload image. Please try again.");
      } finally {
        setIsUploading(false);
      }
    }
  };

  return (
    <div className="max-w-xl mx-auto mt-10">
      <div className="bg-slate-900 border border-slate-800 rounded-2xl p-8 shadow-2xl">
        <div className="flex flex-col items-center mb-6">
          <div className="w-16 h-16 bg-indigo-900/30 rounded-full flex items-center justify-center mb-4">
             <Icons.Smartphone className="w-8 h-8 text-indigo-400" />
          </div>
          <h2 className="text-2xl font-bold text-white">Daily Screen Time</h2>
