    let maxStreak = 0;
    let currentStreak = 0;

    entries.forEach(entry => {
        if (entry.completedHours >= entry.goalHours) {
            currentStreak++;
            maxStreak = Math.max(maxStreak, currentStreak);
        } else {
            currentStreak = 0;
        }
    });
    return maxStreak;
