  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskDesc, setNewTaskDesc] = useState('');
  const [newTaskType, setNewTaskType] = useState<TaskType>(TaskType.WORK);
  const [newTaskDuration, setNewTaskDuration] = useState<number>(1);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const [selectedTaskForUpload, setSelectedTaskForUpload] = useState<string | null>(null);

  // Proof Preview State
  const [previewProof, setPreviewProof] = useState<string | null>(null);
  const [loadingProofId, setLoadingProofId] = useState<string | null>(null);

  // Daily Limit Calculation
  const dailyLimit = user.weeklyGoalHours / 7;

  // --- MOTIVATIONAL QUOTES FOR EMPTY STATE ---
  const quotes = [
      { text: "Discipline is doing what needs to be done, even if you don't want to.", icon: Icons.Target, color: "text-red-400" },
      { text: "Flow state is the ultimate high. Build the walls to protect it.", icon: Icons.Fire, color: "text-orange-400" },
      { text: "Hard work beats talent when talent doesn't work hard.", icon: Icons.BarChart, color: "text-indigo-400" },
      { text: "Consistency is the key to breakthrough. Show up.", icon: Icons.Clock, color: "text-teal-400" },
      { text: "Your future is created by what you do today, not tomorrow.", icon: Icons.Layout, color: "text-slate-400" }
  ];

  const randomQuote = useMemo(() => {
      return quotes[Math.floor(Math.random() * quotes.length)];
  }, []); // Only run once on mount

  // --- FILTER TASKS FOR "DAILY VIEW" ---
  // Show task if: Created TODAY OR Completed TODAY
  const visibleTasks = useMemo(() => {
    const todayStr = new Date().toDateString();
    return tasks.filter(t => {
        const createdToday = new Date(t.createdAt).toDateString() === todayStr;
        const completedToday = t.completedAt ? new Date(t.completedAt).toDateString() === todayStr : false;

        // We show tasks created today (even if pending) OR tasks completed today
        return createdToday || completedToday;
    });
  }, [tasks]);

  // Calculate today's load based on the visible daily tasks
  const todayTasks = visibleTasks.filter(t => t.status !== VerificationStatus.REJECTED);
  const todayUsed = todayTasks.reduce((acc, t) => acc + t.durationHours, 0);

  const formatTimeAgo = (timestamp: number | string) => {
    if (!timestamp) return '';
    const date = new Date(timestamp);
    const now = new Date();
    const seconds = Math.floor((now.getTime() - date.getTime()) / 1000);

    if (seconds < 60) return 'created just now';

    const intervals = [
        { label: 'year', seconds: 31536000 },
        { label: 'month', seconds: 2592000 },
        { label: 'week', seconds: 604800 },
        { label: 'day', seconds: 86400 },
        { label: 'hr', seconds: 3600 },
        { label: 'min', seconds: 60 }
    ];

    for (const i of intervals) {
        const count = Math.floor(seconds / i.seconds);
        if (count >= 1) {
            return `created ${count} ${i.label}${count !== 1 ? 's' : ''} ago`;
        }
    }
    return 'created just now';
  };

  const openCreateModal = () => {
    resetForm();
    setIsModalOpen(true);
  };

  const openEditModal = (task: Task) => {
    setNewTaskTitle(task.title);
    setNewTaskDesc(task.description);
    setNewTaskType(task.type);
    setNewTaskDuration(task.durationHours);
    setEditingTaskId(task.id);
    setIsModalOpen(true);
  };

  const handleSaveTask = async () => {
    if (!newTaskTitle || newTaskDuration <= 0) return;

    if (editingTaskId) {
        // UPDATE EXISTING TASK
        setTasks(prev => prev.map(t => t.id === editingTaskId ? {
            ...t,
            title: newTaskTitle,
            description: newTaskDesc,
            type: newTaskType,
            durationHours: newTaskDuration
        } : t));

        setIsModalOpen(false);
        resetForm();

        const { error } = await supabase.from('tasks').update({
            title: newTaskTitle,
            description: newTaskDesc,
            type: newTaskType,
            duration_hours: newTaskDuration
        }).eq('id', editingTaskId);

        if (error) {
            console.error("Error updating task", error);
            alert("Failed to update task.");
        }

    } else {
        // CREATE NEW TASK
        const tempId = crypto.randomUUID();
        const newTask: Task = {
            id: tempId,
            title: newTaskTitle,
            description: newTaskDesc,
            type: newTaskType,
            durationHours: newTaskDuration,
            createdAt: Date.now(),
            status: VerificationStatus.PENDING
        };

        // Optimistic Update
        setTasks(prev => [newTask, ...prev]);
        setIsModalOpen(false);
        resetForm();

        // DB Insert
        const { data, error } = await supabase.from('tasks').insert({
            user_id: user.googleId,
            title: newTask.title,
            description: newTask.description,
            type: newTask.type,
            duration_hours: newTask.durationHours,
            status: newTask.status,
            created_at: newTask.createdAt // Passing number, supabase handles timestamp conversion if column is timestamp/timestamptz
        }).select();

        // Update with real ID from DB if successful
        if (data && data[0]) {
            setTasks(prev => prev.map(t => t.id === tempId ? { ...t, id: data[0].id } : t));
        }
        if (error) {
            console.error("Error creating task", error);
            setTasks(prev => prev.filter(t => t.id !== tempId));
            alert(`Failed to save task to database: ${error.message}`);
        }
    }
  };

  const resetForm = () => {
    setNewTaskTitle('');
    setNewTaskDesc('');
    setNewTaskDuration(1);
    setNewTaskType(TaskType.WORK);
    setEditingTaskId(null);
  };

  const handleDeleteTask = async (taskId: string) => {
    if (!window.confirm("Are you sure you want to remove this completed task? This cannot be undone.")) {
      return;
    }

    setTasks(prev => prev.filter(t => t.id !== taskId));
    const { error } = await supabase.from('tasks').delete().eq('id', taskId);

    if (error) {
      console.error("Error deleting task", error);
      alert("Failed to delete task from server.");
    }
  };

  // --- LAZY LOADING PROOF ---
  const handleViewProof = async (task: Task) => {
    // If we already have the base64, just show it
    if (task.proofImage) {
      setPreviewProof(task.proofImage);
      return;
    }

    try {
      setLoadingProofId(task.id);
      const { data, error } = await supabase
        .from('tasks')
        .select('proof_image')
        .eq('id', task.id)
        .single();

      if (error) throw error;

      if (data && data.proof_image) {
        // Update local task state to cache the image so we don't fetch again
        setTasks(prev => prev.map(t => t.id === task.id ? { ...t, proofImage: data.proof_image } : t));
        setPreviewProof(data.proof_image);
      } else {
        alert("No proof image found for this task.");
      }
    } catch (err) {
      console.error("Error fetching proof:", err);
      alert("Failed to load proof image.");
    } finally {
      setLoadingProofId(null);
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    const currentTaskId = selectedTaskForUpload; // Capture ID immediately

    if (!file || !currentTaskId) return;

    // Clear the input so the same file can be selected again if needed
    if (fileInputRef.current) fileInputRef.current.value = '';

    const taskIndex = tasks.findIndex(t => t.id === currentTaskId);
    if (taskIndex === -1) return;
    const taskToVerify = tasks[taskIndex];

    setVerifyingId(currentTaskId);
    updateTaskStatus(currentTaskId, VerificationStatus.VERIFYING);

    try {
      // 1. Optimize Image FIRST
      const optimizedFile = await optimizeFile(file);

      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64String = reader.result as string;

        // 2. Verify with Optimized Image
        const result = await verifyTaskProof(taskToVerify, base64String, optimizedFile.type);

        let newStatus = VerificationStatus.PENDING;
        let rejectionReason = "";
        let publicUrl = "";
        let completedAt: number | null = null;

        if (result.verified) {
           // Reuse Base64 string for storage
           publicUrl = base64String;
           newStatus = VerificationStatus.VERIFIED;
           completedAt = Date.now();
        } else {
           newStatus = VerificationStatus.REJECTED;
           rejectionReason = result.reason || "Verification failed";
        }

        // 3. CRITICAL: Update Database BEFORE updating parent stats
        await supabase.from('tasks').update({
          status: newStatus,
          completed_at: completedAt,
          proof_image: publicUrl || null,
          rejection_reason: rejectionReason
        }).eq('id', currentTaskId);

        // 4. Update Local State
        setTasks(prev => prev.map(t => 
            t.id === currentTaskId 
            ? { 
                ...t, 
                status: newStatus, 
                completedAt: completedAt || undefined, 
                proofImage: publicUrl,
                rejectionReason: rejectionReason 
              } 
            : t
        ));

        setVerifyingId(null);
        setSelectedTaskForUpload(null);

        // 5. Trigger Stats Update (No full re-sync)
        if (result.verified) {
           updateCompletedHours(taskToVerify.durationHours);
        } else if (!result.verified) {
           alert(`Verification Failed: ${rejectionReason}`);
        }
      };
      reader.readAsDataURL(optimizedFile);

    } catch (err) {
        console.error("File processing error", err);
        setVerifyingId(null);
        alert("Error processing file. Please try again.");
    }
  };

  const updateTaskStatus = (id: string, status: VerificationStatus) => {
    setTasks(prev => prev.map(t => t.id === id ? { ...t, status } : t));
  };

  const triggerUpload = (id: string) => {
    setSelectedTaskForUpload(id);
    fileInputRef.current?.click();
  };

  return (
    <div className="pb-20 md:pb-0 h-full overflow-y-auto">
      <div className="flex justify-between items-center mb-6">
        <div>
          <h2 className="text-2xl font-bold text-white">Today's Tasks</h2>
          <p className="text-slate-400 text-sm">
             Today's Load: <span className={`${todayUsed > dailyLimit ? 'text-red-400' : 'text-indigo-400'}`}>{todayUsed.toFixed(1)}h</span> / {dailyLimit.toFixed(1)}h limit
          </p>
        </div>
        <button 
          onClick={openCreateModal}
          className="bg-indigo-600 hover:bg-indigo-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-colors font-medium shadow-lg shadow-indigo-900/20"
        >
          <Icons.Plus className="w-5 h-5" />
          Add Task
        </button>
      </div>

      <div className="space-y-4">
        {visibleTasks.length === 0 && (
            <div className="flex flex-col items-center justify-center py-20 text-center animate-in fade-in zoom-in-95 duration-500">
                <randomQuote.icon className={`w-20 h-20 mb-6 ${randomQuote.color} opacity-80`} />
                <h3 className="text-xl font-medium text-white max-w-lg leading-relaxed">
                  "{randomQuote.text}"
                </h3>
                <p className="text-slate-600 mt-4 text-sm">Start your day by adding a new task.</p>
            </div>
        )}

        {visibleTasks.map(task => (
          <div key={task.id} className={`bg-slate-900 border ${task.status === VerificationStatus.VERIFIED ? 'border-green-900/50 bg-green-900/5' : task.status === VerificationStatus.REJECTED ? 'border-red-900/50' : 'border-slate-800'} rounded-xl p-5 flex flex-col md:flex-row justify-between items-start md:items-center gap-4 transition-all hover:border-slate-700 group relative`}>

            {task.status !== VerificationStatus.VERIFIED && task.status !== VerificationStatus.VERIFYING && (
                <button 
                    onClick={() => openEditModal(task)}
                    className="absolute top-4 right-4 text-slate-500 hover:text-indigo-400 p-1 rounded hover:bg-slate-800 transition-colors"
                    title="Edit Task"
                >
                    <Icons.Edit className="w-4 h-4" />
                </button>
            )}

            <div className="flex-1">
              <div className="flex items-center gap-2 mb-1 flex-wrap">
                <span className={`text-xs px-2 py-0.5 rounded border ${task.type === TaskType.STUDY ? 'bg-indigo-950/50 border-indigo-900 text-indigo-400' : 'bg-teal-950/50 border-teal-900 text-teal-400'}`}>
                  {task.type}
                </span>
                <span className="text-xs text-slate-500 flex items-center gap-1">
                  <Icons.Clock className="w-3 h-3" /> {task.durationHours}h
                </span>

                <span className="text-xs text-slate-600 hidden sm:inline">•</span>
                <span className="text-xs text-slate-500">
                  {formatTimeAgo(task.createdAt)}
                </span>

                {task.status === VerificationStatus.REJECTED && (
                    <span className="text-xs text-red-400 bg-red-950/30 px-2 rounded">Rejected: {task.rejectionReason}</span>
                )}
              </div>
              <h3 className="text-lg font-semibold text-slate-100 pr-8">{task.title}</h3>
              <p className="text-slate-400 text-sm mt-1">{task.description}</p>

              {/* UPDATED: View Proof button logic checks status NOT task.proofImage presence */}
              {task.status === VerificationStatus.VERIFIED && (
                  <button 
                    onClick={() => handleViewProof(task)}
                    disabled={loadingProofId === task.id}
                    className="flex items-center gap-1.5 text-xs text-indigo-400 hover:text-indigo-300 hover:bg-indigo-950/30 px-2 py-1 -ml-2 mt-2 rounded transition-colors disabled:opacity-50 disabled:cursor-wait"
                  >
                    {loadingProofId === task.id ? <Icons.Loader className="w-4 h-4 animate-spin" /> : <Icons.Eye className="w-4 h-4" />}
                    View Proof
                  </button>
              )}
            </div>

            <div className="w-full md:w-auto flex justify-end mt-4 md:mt-0">
               {task.status === VerificationStatus.VERIFIED ? (
                 <div className="flex items-center gap-2">
                    <div className="flex items-center gap-2 text-green-500 px-4 py-2 bg-green-950/20 rounded-lg border border-green-900/50">
                       <Icons.CheckCircle className="w-5 h-5" />
                       <span className="font-medium">Completed</span>
                    </div>
                    <button 
                      onClick={() => handleDeleteTask(task.id)}
                      className="p-2 text-slate-500 hover:text-red-400 hover:bg-red-950/30 rounded-lg transition-colors border border-transparent hover:border-red-900/50"
                      title="Remove Task"
                    >
                      <Icons.Trash className="w-5 h-5" />
                    </button>
                 </div>
               ) : verifyingId === task.id ? (
                 <div className="flex items-center gap-2 text-indigo-400 px-4 py-2 animate-pulse">
                    <Icons.Shield className="w-5 h-5 animate-bounce" />
                    <span>AI Verifying...</span>
                 </div>
               ) : (
                 <div className="w-full md:w-auto">
                    <button 
                        onClick={() => triggerUpload(task.id)}
                        className="w-full md:w-auto flex items-center justify-center gap-2 bg-slate-800 hover:bg-slate-700 text-slate-200 px-4 py-2 rounded-lg border border-slate-700 transition-colors"
                    >
                        <Icons.Upload className="w-4 h-4" />
                        Submit Proof
                    </button>
                 </div>
               )}
            </div>
          </div>
        ))}
      </div>

      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={handleFileUpload} 
        accept="image/*,application/pdf"
        className="hidden" 
      />

      {/* Proof Preview Modal */}
      {previewProof && (
          <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/90 backdrop-blur-sm" onClick={() => setPreviewProof(null)}>
              <div className="relative max-w-4xl w-full bg-slate-900 rounded-xl overflow-hidden shadow-2xl flex flex-col border border-slate-700 animate-in fade-in zoom-in-95 duration-200" onClick={e => e.stopPropagation()}>
                  <div className="flex justify-between items-center p-4 border-b border-slate-800 bg-slate-950/50">
                      <h3 className="text-white font-medium flex items-center gap-2">
                          <Icons.Shield className="w-4 h-4 text-indigo-400" />
                          Verified Proof
                      </h3>
                      <button onClick={() => setPreviewProof(null)} className="text-slate-400 hover:text-white transition-colors">
                          <Icons.XCircle className="w-6 h-6" />
                      </button>
                  </div>
                  <div className="flex-1 bg-black/50 flex items-center justify-center p-1 min-h-[50vh] max-h-[80vh] overflow-auto">
                      {previewProof.includes('application/pdf') ? (
                          <object data={previewProof} type="application/pdf" className="w-full h-[70vh] rounded bg-white">
                              <div className="flex flex-col items-center justify-center h-full text-slate-400 gap-2">
                                  <p>PDF preview not available.</p>
                                  <a href={previewProof} download="proof.pdf" className="text-indigo-400 hover:underline">Download PDF</a>
                              </div>
                          </object>
                      ) : (
                          <img src={previewProof} alt="Proof" className="max-w-full max-h-[75vh] object-contain rounded shadow-lg" />
                      )}
                  </div>
                   <div className="p-4 border-t border-slate-800 flex justify-between items-center bg-slate-900">
                      <span className="text-xs text-slate-500">Verified by Goal Guardian AI</span>
                      <a 
                          href={previewProof} 
                          download={`proof_${Date.now()}.${previewProof.includes('application/pdf') ? 'pdf' : 'png'}`} 
                          className="flex items-center gap-2 px-4 py-2 bg-slate-800 hover:bg-slate-700 text-slate-200 rounded-lg text-sm font-medium transition-colors"
                      >
                          <Icons.Upload className="w-4 h-4 rotate-180" />
                          Download File
                      </a>
                  </div>
              </div>
          </div>
      )}

      {/* Create/Edit Task Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-slate-900 border border-slate-700 w-full max-w-md rounded-2xl p-6 shadow-2xl">
            <h3 className="text-xl font-bold text-white mb-4">{editingTaskId ? 'Edit Task' : 'New Task'}</h3>

            <div className="space-y-4">
              <div>
                <label className="block text-sm text-slate-400 mb-1">Title</label>
                <input 
                  type="text" 
                  value={newTaskTitle}
                  onChange={(e) => setNewTaskTitle(e.target.value)}
                  className="w-full bg-slate-800 border border-slate-700 rounded-lg px-3 py-2 text-white focus:outline-none focus:border-indigo-500"
                  placeholder="e.g., Complete Chapter 4 Math"
                />
              </div>

              <div>
                <label className="block text-sm text-slate-400 mb-1">Description (for AI Verification)</label>
                <textarea 
                  value={newTaskDesc}
                  onChange={(e) => setNewTaskDesc(e.target.value)}
                  className="w-full bg-slate-800 border border-slate-700 rounded-lg px-3 py-2 text-white focus:outline-none focus:border-indigo-500 h-24 resize-none"
                  placeholder="Describe exactly what will be visible in the proof..."
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                   <label className="block text-sm text-slate-400 mb-1">Type</label>
                   <select 
                    value={newTaskType}
                    onChange={(e) => setNewTaskType(e.target.value as TaskType)}
                    className="w-full bg-slate-800 border border-slate-700 rounded-lg px-3 py-2 text-white focus:outline-none focus:border-indigo-500"
                   >
                     <option value={TaskType.STUDY}>Study</option>
                     <option value={TaskType.WORK}>Work</option>
                   </select>
                </div>
                <div>
                   <label className="block text-sm text-slate-400 mb-1">Duration (Hours)</label>
                   <input 
                    type="number" 
                    min="0.5"
                    step="0.5"
                    value={newTaskDuration}
                    onChange={(e) => setNewTaskDuration(parseFloat(e.target.value))}
                    className="w-full bg-slate-800 border border-slate-700 rounded-lg px-3 py-2 text-white focus:outline-none focus:border-indigo-500"
                   />
                </div>
              </div>
            </div>

            <div className="flex gap-3 mt-6">
              <button 
                onClick={() => setIsModalOpen(false)}
                className="flex-1 px-4 py-2 bg-slate-800 text-slate-300 rounded-lg hover:bg-slate-700"
              >
                Cancel
              </button>
              <button 
                onClick={handleSaveTask}
                className="flex-1 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 font-medium"
              >
                {editingTaskId ? 'Save Changes' : 'Create'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Sidebar } from './components/Sidebar';
import { Dashboard } from './components/Dashboard';
import { TaskList } from './components/TaskList';
import { ScreenTimeUpload } from './components/ScreenTimeUpload';
import { History } from './components/History';
import { Auth } from './components/Auth';
import { Icons } from './components/Icons';
import { UserProfile, WeeklyStats, Task, HistoryEntry, VerificationStatus } from './types';
import { calculateWeeklyRating } from './services/geminiService';
import { supabase } from './services/supabase';

// --- DATE HELPERS ---

const getWeekIdFromDate = (date: Date) => {
  const d = new Date(date);
  d.setHours(0, 0, 0, 0);
  d.setDate(d.getDate() + 4 - (d.getDay() || 7));
  const yearStart = new Date(d.getFullYear(), 0, 1);
  const weekNo = Math.ceil((((d.getTime() - yearStart.getTime()) / 86400000) + 1) / 7);
  return `${d.getFullYear()}-W${String(weekNo).padStart(2, '0')}`;
};

// Robust ISO Week ID Calculator (YYYY-Www)
const getCurrentWeekId = () => getWeekIdFromDate(new Date());

const getPreviousWeekId = (weekId: string) => {
  // Approximate reverse calculation to find the previous week ID
  // We parse the year and week, find a date in that week, subtract 7 days, and recalculate ID
  const [yStr, wStr] = weekId.split('-W');
  const y = parseInt(yStr, 10);
  const w = parseInt(wStr, 10);

  // Simple heuristic: 4th of Jan is always in week 1
  const d = new Date(y, 0, 4);
  // Add (w - 1) weeks to get to the target week
  d.setDate(d.getDate() + (w - 1) * 7);
  // Subtract 7 days to get previous week
  d.setDate(d.getDate() - 7);

  return getWeekIdFromDate(d);
};

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [currentView, setCurrentView] = useState('dashboard');

  // User State
  const [user, setUser] = useState<UserProfile | null>(null);
  const [stats, setStats] = useState<WeeklyStats | null>(null);
  const [history, setHistory] = useState<HistoryEntry[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  // Check for existing session
  useEffect(() => {
    const savedUser = localStorage.getItem('focusforge_user');
    if (savedUser) {
      const parsedUser = JSON.parse(savedUser);
      setUser(parsedUser);
      setIsAuthenticated(true);
      fetchUserData(parsedUser.googleId);
    }
  }, []);

  const fetchUserData = async (googleId: string, backgroundSync = false) => {
    if (!backgroundSync) setIsLoading(true);
    const currentWeekId = getCurrentWeekId();

    try {
      // Parallel execution for faster load times
      // CRITICAL OPTIMIZATION: Exclude 'proof_image' from tasks fetch. It is huge (Base64).
      // We load it on-demand in TaskList.
      const [profileRes, tasksRes, historyRes, currentStatsRes] = await Promise.all([
        supabase.from('profiles').select('*').eq('google_id', googleId).single(),
        supabase
          .from('tasks')
          .select('id, title, description, type, duration_hours, created_at, completed_at, status, rejection_reason') // Explicitly select columns to avoid downloading images
          .eq('user_id', googleId)
          .order('created_at', { ascending: false }), 
        supabase.from('weekly_stats').select('*').eq('user_id', googleId).neq('week_id', currentWeekId).order('week_id', { ascending: true }),
        supabase.from('weekly_stats').select('*').eq('user_id', googleId).eq('week_id', currentWeekId).single()
      ]);

      // 1. Process Profile
      let currentUserGoal = 80;
      if (profileRes.data && user) {
         currentUserGoal = profileRes.data.weekly_goal_hours || 80;
         if (user.weeklyGoalHours !== currentUserGoal) {
             const updatedUser = { ...user, weeklyGoalHours: currentUserGoal };
             setUser(updatedUser);
             localStorage.setItem('focusforge_user', JSON.stringify(updatedUser));
         }
      }

      // 2. Process Tasks
      let formattedTasks: Task[] = [];
      if (tasksRes.data) {
        formattedTasks = tasksRes.data.map((t: any) => ({
          id: t.id,
          title: t.title,
          description: t.description,
          type: t.type,
          durationHours: t.duration_hours,
          // Convert to timestamp numbers for reliable sorting/math
          createdAt: new Date(t.completed_at || t.created_at).getTime(), 
          completedAt: t.completed_at ? new Date(t.completed_at).getTime() : undefined,
          status: t.status,
          // proofImage is undefined here to save bandwidth. Loaded lazy.
          rejectionReason: t.rejection_reason
        }));
        // Sort in memory to ensure order
        formattedTasks.sort((a, b) => b.createdAt - a.createdAt);
        setTasks(formattedTasks);
      }

      // 3. Process History
      let formattedHistory: HistoryEntry[] = [];
      if (historyRes.data) {
        formattedHistory = historyRes.data.map((h: any) => ({
          id: h.id,
          weekId: h.week_id,
          goalHours: h.goal_hours,
          completedHours: h.completed_hours,
          screenTimeHours: h.screen_time_hours,
          rating: h.rating,
          streakActive: h.streak_active,
          startDate: h.start_date,
          endDate: h.end_date
        }));
        setHistory(formattedHistory);
      }

      // 4. Process Current Stats & Self-Healing
      const now = new Date();
      const currentDay = now.getDay(); 
      const distanceToMonday = currentDay === 0 ? 6 : currentDay - 1;
      const monday = new Date(now);
      monday.setDate(now.getDate() - distanceToMonday);
      monday.setHours(0, 0, 0, 0);
      const nextMonday = new Date(monday);
      nextMonday.setDate(monday.getDate() + 7);

      const actualCompletedHours = formattedTasks
        .filter(t => {
           if (t.status !== VerificationStatus.VERIFIED || !t.completedAt) return false;
           const d = new Date(t.completedAt);
           return d >= monday && d < nextMonday;
        })
        .reduce((acc, t) => acc + t.durationHours, 0);

      const statsData = currentStatsRes.data;
      let currentStatsObj: WeeklyStats;

      if (statsData) {
        currentStatsObj = {
          weekId: statsData.week_id,
          goalHours: statsData.goal_hours,
          completedHours: statsData.completed_hours,
          screenTimeHours: statsData.screen_time_hours,
          rating: statsData.rating,
          streakActive: statsData.streak_active,
          startDate: statsData.start_date,
          endDate: statsData.end_date
        };

        // Self-heal check (only if significant difference)
        if (Math.abs(statsData.completed_hours - actualCompletedHours) > 0.1) {
            currentStatsObj.completedHours = actualCompletedHours;
            // Fire and forget update
            supabase.from('weekly_stats')
              .update({ completed_hours: actualCompletedHours })
              .eq('week_id', currentWeekId)
              .eq('user_id', googleId)
              .then(({ error }) => { if (error) console.error("Background stat sync failed", error); });
        }
        setStats(currentStatsObj);
      } else {
        // Create new week
        currentStatsObj = {
          weekId: currentWeekId,
          startDate: monday.toLocaleDateString(),
          endDate: new Date(nextMonday.getTime() - 1).toLocaleDateString(),
          goalHours: currentUserGoal,
          completedHours: actualCompletedHours,
          screenTimeHours: 0,
          rating: 0,
          streakActive: true
        };
        setStats(currentStatsObj);
        supabase.from('weekly_stats').insert({
          user_id: googleId,
          week_id: currentStatsObj.weekId,
          start_date: currentStatsObj.startDate,
          end_date: currentStatsObj.endDate,
          goal_hours: currentStatsObj.goalHours,
          completed_hours: currentStatsObj.completedHours
        }).then(({ error }) => { if (error) console.error("Error creating weekly stats", error); });
      }

      // --- STREAK CALCULATION LOGIC ---
      let streak = 0;
      let checkWeekId = currentWeekId;

      if (currentStatsObj.completedHours >= currentStatsObj.goalHours) {
        streak++;
        checkWeekId = getPreviousWeekId(checkWeekId);
      } else {
        checkWeekId = getPreviousWeekId(checkWeekId);
      }

      const reversedHistory = [...formattedHistory].sort((a, b) => b.weekId.localeCompare(a.weekId));

      for (const entry of reversedHistory) {
         if (entry.weekId !== checkWeekId) break; 
         if (entry.completedHours >= entry.goalHours) {
           streak++;
           checkWeekId = getPreviousWeekId(checkWeekId);
         } else {
           break;
         }
      }

      if (user && user.currentStreak !== streak) {
          setUser(prev => {
              if (!prev) return null;
              const updated = { ...prev, currentStreak: streak };
              localStorage.setItem('focusforge_user', JSON.stringify(updated));
              return updated;
          });
      }

    } catch (err) {
        console.error("Critical error fetching user data:", err);
    } finally {
        if (!backgroundSync) setIsLoading(false);
    }
  };

  const handleLogin = async (userData: any) => {
    const newUser: UserProfile = {
      name: userData.name,
      email: userData.email,
      avatarUrl: userData.avatarUrl,
      googleId: userData.googleId,
      weeklyGoalHours: 80, 
      currentStreak: 0 
    };
    setUser(newUser);
    localStorage.setItem('focusforge_user', JSON.stringify(newUser));
    setIsAuthenticated(true);

    // Fire and forget profile upsert
    supabase.from('profiles').select('weekly_goal_hours').eq('google_id', userData.googleId).single()
      .then(({data}) => {
         const userGoal = data?.weekly_goal_hours || 80;
         if (userGoal !== 80) {
             setUser(prev => prev ? { ...prev, weeklyGoalHours: userGoal } : prev);
         }
         return supabase.from('profiles').upsert({
            google_id: userData.googleId,
            email: userData.email,
            name: userData.name,
            avatar_url: userData.avatarUrl,
            weekly_goal_hours: userGoal 
        }, { onConflict: 'google_id' });
      });

    fetchUserData(userData.googleId);
  };

  const handleLogout = () => {
    localStorage.removeItem('focusforge_user');
    setUser(null);
    setStats(null);
    setTasks([]);
    setHistory([]);
    setIsAuthenticated(false);
  };

  const updateWeeklyGoal = async (newGoal: number) => {
    if (!user) return;

    const updatedUser = { ...user, weeklyGoalHours: newGoal };
    setUser(updatedUser);
    localStorage.setItem('focusforge_user', JSON.stringify(updatedUser));

    // Optimistic UI updates, no need to wait or refetch
    await supabase.from('profiles').update({ weekly_goal_hours: newGoal }).eq('google_id', user.googleId);

    if (stats) {
        setStats({ ...stats, goalHours: newGoal });
        await supabase.from('weekly_stats')
            .update({ goal_hours: newGoal })
            .eq('user_id', user.googleId)
            .eq('week_id', stats.weekId);
    }
  };

  const updateCompletedHours = async (hoursToAdd: number) => {
     if (!user || !stats) return;

     const newCompleted = stats.completedHours + hoursToAdd;
     const newRating = await calculateWeeklyRating(
       newCompleted, 
       stats.goalHours, 
       stats.screenTimeHours
     );

     // Optimistic Update
     setStats(prev => prev ? ({ ...prev, completedHours: newCompleted, rating: newRating }) : null);

     // Background DB Update
     await supabase
       .from('weekly_stats')
       .update({ completed_hours: newCompleted, rating: newRating })
       .eq('user_id', user.googleId)
       .eq('week_id', stats.weekId);

     // REMOVED: fetchUserData call. Local state is already accurate.
     // This prevents the "way too time taking" sync after every task.
  };

  const handleScreenTimeSubmit = async (hours: number, image: string) => {
     if (!user || !stats) return;

     const newScreenTime = stats.screenTimeHours + hours;
     const newRating = await calculateWeeklyRating(
       stats.completedHours, 
       stats.goalHours, 
       newScreenTime
     );

     setStats(prev => prev ? ({ ...prev, screenTimeHours: newScreenTime, rating: newRating }) : null);

     await supabase
       .from('weekly_stats')
       .update({ screen_time_hours: newScreenTime, rating: newRating })
       .eq('user_id', user.googleId)
       .eq('week_id', stats.weekId);
  };

  if (!isAuthenticated || !user) {
    return <Auth onLogin={handleLogin} />;
  }

  if (isLoading || !stats) {
    return <div className="min-h-screen bg-[#020617] flex items-center justify-center text-white">
        <div className="flex flex-col items-center gap-4">
            <Icons.Loader className="w-8 h-8 text-indigo-500 animate-spin" />
            <p className="text-slate-400 font-medium">Syncing data...</p>
        </div>
    </div>;
  }

  return (
    <div className="flex flex-col md:flex-row min-h-screen bg-[#020617] text-slate-50 font-sans">
      <Sidebar 
        user={user} 
        currentView={currentView} 
        setView={setCurrentView} 
        onLogout={handleLogout}
        onUpdateGoal={updateWeeklyGoal}
      />

      <main className="flex-1 md:ml-64 p-4 md:p-8 overflow-y-auto h-screen">
        <div className="max-w-7xl mx-auto h-full">
          {currentView === 'dashboard' && <Dashboard user={user} stats={stats} tasks={tasks} />}
          {currentView === 'tasks' && <TaskList tasks={tasks} setTasks={setTasks} user={user} updateCompletedHours={updateCompletedHours} />}
          {currentView === 'screentime' && <ScreenTimeUpload user={user} onSubmit={handleScreenTimeSubmit} />}
          {currentView === 'history' && <History history={[...history, { ...stats, id: 'current' } as HistoryEntry]} tasks={tasks} />}
        </div>
      </main>
    </div>
  );
};

export default App;
